package llmgen

import (
	"bytes"
	"fmt"
	"go/format"
)

// GeneratePersisterAdapter generates the llmpersist adapter source code that
// wraps the generated queries.Runner to satisfy llm.Persister.
//
// The generated file lives at shipq/lib/llmpersist/zz_generated_persister.go
// and provides:
//
//   - A Persister struct wrapping queries.Runner
//   - A New(runner) constructor
//   - InsertConversation, UpdateConversation, InsertMessage methods
//
// The generated adapter translates between the llm.* param/result types and
// the queries.* param/result types produced by the querydef compiler.
func GeneratePersisterAdapter(modulePath string) ([]byte, error) {
	var buf bytes.Buffer

	llmPkg := modulePath + "/shipq/lib/llm"
	queriesPkg := modulePath + "/shipq/queries"

	buf.WriteString("// Code generated by shipq. DO NOT EDIT.\n")
	buf.WriteString("package llmpersist\n\n")

	buf.WriteString("import (\n")
	buf.WriteString("\t\"context\"\n")
	buf.WriteString("\t\"time\"\n")
	buf.WriteString("\n")
	fmt.Fprintf(&buf, "\t%q\n", llmPkg)
	fmt.Fprintf(&buf, "\t%q\n", queriesPkg)
	buf.WriteString(")\n\n")

	// Persister struct
	buf.WriteString("// Persister wraps queries.Runner to satisfy llm.Persister.\n")
	buf.WriteString("type Persister struct {\n")
	buf.WriteString("\trunner queries.Runner\n")
	buf.WriteString("}\n\n")

	// Constructor
	buf.WriteString("// New creates a new Persister backed by the given query runner.\n")
	buf.WriteString("func New(runner queries.Runner) *Persister {\n")
	buf.WriteString("\treturn &Persister{runner: runner}\n")
	buf.WriteString("}\n\n")

	// Compile-time interface check
	buf.WriteString("// Compile-time check that Persister satisfies llm.Persister.\n")
	buf.WriteString("var _ llm.Persister = (*Persister)(nil)\n\n")

	// InsertConversation
	buf.WriteString("// InsertConversation creates a new conversation row and returns its ID and public ID.\n")
	buf.WriteString("func (p *Persister) InsertConversation(ctx context.Context, params llm.InsertConversationParams) (llm.ConversationRow, error) {\n")
	buf.WriteString("\tstartedAt := params.StartedAt\n")
	buf.WriteString("\tif startedAt.IsZero() {\n")
	buf.WriteString("\t\tstartedAt = time.Now()\n")
	buf.WriteString("\t}\n\n")
	buf.WriteString("\tresult, err := p.runner.InsertLLMConversation(ctx, queries.InsertLLMConversationParams{\n")
	buf.WriteString("\t\tPublicId:    params.PublicID,\n")
	buf.WriteString("\t\tJobId:       params.JobID,\n")
	buf.WriteString("\t\tChannelName: params.ChannelName,\n")
	buf.WriteString("\t\tAccountId:   params.AccountID,\n")
	buf.WriteString("\t\tProvider:    params.Provider,\n")
	buf.WriteString("\t\tModel:       params.Model,\n")
	buf.WriteString("\t\tStatus:      string(params.Status),\n")
	buf.WriteString("\t\tStartedAt:   startedAt.Format(time.RFC3339),\n")
	buf.WriteString("\t})\n")
	buf.WriteString("\tif err != nil {\n")
	buf.WriteString("\t\treturn llm.ConversationRow{}, err\n")
	buf.WriteString("\t}\n")
	buf.WriteString("\treturn llm.ConversationRow{ID: result.Id, PublicID: result.PublicId}, nil\n")
	buf.WriteString("}\n\n")

	// UpdateConversation
	buf.WriteString("// UpdateConversation updates the status, token counts, and tool call count\n")
	buf.WriteString("// on an existing conversation row once the turn is complete.\n")
	buf.WriteString("func (p *Persister) UpdateConversation(ctx context.Context, params llm.UpdateConversationParams) error {\n")
	buf.WriteString("\tvar completedAt *string\n")
	buf.WriteString("\tif !params.CompletedAt.IsZero() {\n")
	buf.WriteString("\t\ts := params.CompletedAt.Format(time.RFC3339)\n")
	buf.WriteString("\t\tcompletedAt = &s\n")
	buf.WriteString("\t}\n\n")
	buf.WriteString("\tvar errorMessage *string\n")
	buf.WriteString("\tif params.ErrorMessage != \"\" {\n")
	buf.WriteString("\t\terrorMessage = &params.ErrorMessage\n")
	buf.WriteString("\t}\n\n")
	buf.WriteString("\t_, err := p.runner.UpdateLLMConversation(ctx, queries.UpdateLLMConversationParams{\n")
	buf.WriteString("\t\tId:            params.ID,\n")
	buf.WriteString("\t\tStatus:        string(params.Status),\n")
	buf.WriteString("\t\tTotalInputTokens:  params.InputTokens,\n")
	buf.WriteString("\t\tTotalOutputTokens: params.OutputTokens,\n")
	buf.WriteString("\t\tToolCallCount:     params.ToolCallCount,\n")
	buf.WriteString("\t\tErrorMessage:      errorMessage,\n")
	buf.WriteString("\t\tCompletedAt:       completedAt,\n")
	buf.WriteString("\t})\n")
	buf.WriteString("\treturn err\n")
	buf.WriteString("}\n\n")

	// InsertMessage
	buf.WriteString("// InsertMessage appends a single message to an existing conversation.\n")
	buf.WriteString("func (p *Persister) InsertMessage(ctx context.Context, params llm.InsertMessageParams) error {\n")
	buf.WriteString("\tvar toolName *string\n")
	buf.WriteString("\tif params.ToolName != \"\" {\n")
	buf.WriteString("\t\ttoolName = &params.ToolName\n")
	buf.WriteString("\t}\n\n")
	buf.WriteString("\tvar toolCallID *string\n")
	buf.WriteString("\tif params.ToolCallID != \"\" {\n")
	buf.WriteString("\t\ttoolCallID = &params.ToolCallID\n")
	buf.WriteString("\t}\n\n")
	buf.WriteString("\tvar content *string\n")
	buf.WriteString("\tif params.Content != \"\" {\n")
	buf.WriteString("\t\tcontent = &params.Content\n")
	buf.WriteString("\t}\n\n")
	buf.WriteString("\t_, err := p.runner.InsertLLMMessage(ctx, queries.InsertLLMMessageParams{\n")
	buf.WriteString("\t\tConversationId: params.ConversationID,\n")
	buf.WriteString("\t\tRole:           string(params.Role),\n")
	buf.WriteString("\t\tContent:        content,\n")
	buf.WriteString("\t\tToolName:       toolName,\n")
	buf.WriteString("\t\tToolCallId:     toolCallID,\n")
	buf.WriteString("\t})\n")
	buf.WriteString("\treturn err\n")
	buf.WriteString("}\n")

	formatted, err := format.Source(buf.Bytes())
	if err != nil {
		// Return unformatted source for debugging.
		return buf.Bytes(), fmt.Errorf("failed to format generated persister adapter: %w", err)
	}

	return formatted, nil
}
